CREATE TABLE Employees ( id INT PRIMARY KEY, name VARCHAR(50) NOT NULL, salary INT NOT NULL );

-- This will cause a NULL value error because salary is NOT NULL
INSERT INTO Employees (id, name, salary) VALUES (1, 'John Doe', NULL);

-- Fix by inserting a valid salary
INSERT INTO Employees (id, name, salary) VALUES (1, 'John Doe', 50000);

-- Or alter the table to allow NULL in salary
ALTER TABLE Employees ALTER COLUMN salary DROP NOT NULL;

-- Now NULL values are allowed
INSERT INTO Employees (id, name, salary) VALUES (2, 'Jane Smith', NULL);

-- Using COALESCE to handle NULLs in queries
SELECT id, name, COALESCE(salary, 0) AS salary FROM Employees;

